import java.util.regex.*;

public class Main {
    public static void main(String[] args) {
        // Email validation
        String emailPattern = "^[\\w.-]+@[\\w.-]+\\.\\w{2,}$";
        String[] emails = {"user@example.com", "invalid@", "test@test.co.uk"};

        for (String email : emails) {
            System.out.println(email + ": " + email.matches(emailPattern));
        }

        // Extract phone numbers
        String text = "Contact: 555-1234 or 555-5678";
        Pattern phonePattern = Pattern.compile("\\d{3}-\\d{4}");
        Matcher matcher = phonePattern.matcher(text);

        while (matcher.find()) {
            System.out.println("Found: " + matcher.group() + 
                " at (" + matcher.start() + "-" + matcher.end() + ")");
        }

        // Replace all
        String clean = "Hello 123 World 456".replaceAll("\\d+", "NUM");
        System.out.println("Cleaned: " + clean);

        // Split
        String[] parts = "apple,banana;cherry|date".split("[,;|]");
        for (String part : parts) {
            System.out.println("Part: " + part);
        }
    }
}
